SELECT COUNT(*) FROM app_admin_permission_change_log
AND target_type = #{targetType}
AND action = #{action}
AND operator LIKE CONCAT('%', #{operator}, '%')
AND (target_key LIKE CONCAT('%', #{keyword}, '%') OR target_name LIKE CONCAT('%', #{keyword}, '%') OR change_summary LIKE CONCAT('%', #{keyword}, '%'))

SELECT id, target_type AS targetType, target_id AS targetId, target_key AS targetKey, target_name AS targetName, action, operator, change_summary AS changeSummary, before_json AS beforeJson, after_json AS afterJson, created_at AS createdAt FROM app_admin_permission_change_log
AND target_type = #{targetType}
AND action = #{action}
AND operator LIKE CONCAT('%', #{operator}, '%')
AND (target_key LIKE CONCAT('%', #{keyword}, '%') OR target_name LIKE CONCAT('%', #{keyword}, '%') OR change_summary LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY created_at DESC, id DESC LIMIT #{limit} OFFSET #{offset}
